mapper.delete:
DELETE t FROM BRD_POST_FILE_THUMB t
  JOIN BRD_POST_FILE f ON f.file_no = t.file_no
 WHERE f.post_no = #{postNo}

mapper.select:
SELECT p.post_no, p.board_gbn_cd, p.board_cat_gbn_cd, p.title, p.view_cnt, p.like_cnt, p.comment_cnt, p.create_ts, p.update_ts, COALESCE(m.nickname, '관리자') AS nickname, cat.code_nm AS cat_nm, (SELECT COALESCE(SUM(f.download_cnt), 0) FROM BRD_POST_FILE f WHERE f.post_no = p.post_no AND f.del_yn = 'N') AS total_download_cnt, (SELECT t.file_path FROM BRD_POST_FILE_THUMB t JOIN BRD_POST_FILE f2 ON f2.file_no = t.file_no WHERE f2.post_no = p.post_no AND f2.del_yn = 'N' AND t.thumb_typ_cd = '01' ORDER BY t.thumb_no ASC LIMIT 1) AS thumb_file_path FROM BRD_POST_MST p LEFT JOIN MEM_JOIN_INFO m ON m.member_no = p.member_no LEFT JOIN COM_CODE_DTL cat ON cat.code_grp_id = 'C014' AND cat.code_id = p.board_cat_gbn_cd AND cat.use_yn = 'Y' WHERE p.board_gbn_cd = '04' AND p.del_yn = 'N' AND p.approval_yn = 'Y'
AND p.board_cat_gbn_cd = #{boardCatGbnCd}
ORDER BY total_download_cnt DESC, p.post_no DESC
ORDER BY p.create_ts DESC, p.post_no DESC
LIMIT #{pageSize} OFFSET #{offset}
